code.C:
#include <stdio.h>
int main(){printf("A pointer to an int points to a memory location holding an int. Adding 1 to the pointer moves it to the next int (address increases by sizeof(int)). Example:
int arr[3] = {5,10,15};
int *p = arr; // points to arr[0]
printf("%d", *(p+2)); // prints 15
p++; // now points to arr[1]
printf("%d", *p); // prints 10
Pointer subtraction gives the number of elements between two pointers of the same array.");return 0;}

